import React from 'react';
import { Link } from 'react-router-dom';
import { useContent } from '../../context/ContentContext';
import './CatalogDropdown.css';

const CatalogDropdown = () => {
  const { catalogItems, categories } = useContent();

  const getRouteForItem = (item) => {
    const routes = {
      'Пользователи': '/catalog/users',
      'Персонажи': '/catalog/characters',
      'Тайтлы': '/catalog/titles',
      'Сейчас читают': '/catalog/reading-now',
      'Коллекции': '/catalog/collections',
      'Отзывы и Рецензии': '/catalog/reviews'
    };
    return routes[item] || '/catalog';
  };

  const getIconForItem = (item) => {
    const icons = {
      'Пользователи': 'fa-users',
      'Персонажи': 'fa-user-friends',
      'Тайтлы': 'fa-star',
      'Сейчас читают': 'fa-eye',
      'Коллекции': 'fa-folder',
      'Отзывы и Рецензии': 'fa-comment-alt'
    };
    return icons[item] || 'fa-tag';
  };

  return (
    <div className="catalog-dropdown">
      <div className="dropdown-container">
        <div className="left-section">
          <h3 className="dropdown-title">Каталог</h3>
          <ul className="catalog-list">
            {catalogItems.map((item, index) => (
              <li key={index} className="catalog-item">
                <Link to={getRouteForItem(item)} className="catalog-link">
                  <i className={`fas ${getIconForItem(item)}`}></i>
                  {item}
                </Link>
              </li>
            ))}
          </ul>
        </div>
        
        <div className="right-section">
          <h3 className="dropdown-title">Категории</h3>
          <div className="categories-grid">
            {categories.map(category => (
              <CategoryCard 
                key={category}
                title={category}
                icon={getCategoryIcon(category)}
                color={getCategoryColor(category)}
              />
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

const CategoryCard = ({ title, icon, color }) => (
  <Link to={`/catalog/category/${title.toLowerCase().replace(/[\s-]+/g, '-')}`} className="category-card">
    <div className="category-icon" style={{ backgroundColor: color }}>
      <i className={`fas ${icon}`}></i>
    </div>
    <span className="category-title">{title}</span>
  </Link>
);

const getCategoryIcon = (category) => {
  const icons = {
    'Манга': 'fa-book',
    'OEL-манга': 'fa-globe',
    'Манхва': 'fa-flag',
    'Маньхуа': 'fa-paint-brush',
    'Руманга': 'fa-map-marker',
    'Комикс': 'fa-user',
    'Видео': 'fa-video'
  };
  return icons[category] || 'fa-tag';
};

const getCategoryColor = (category) => {
  const colors = {
    'Манга': '#ff6b6b',
    'OEL-манга': '#4ecdc4',
    'Манхва': '#45b7d1',
    'Маньхуа': '#96ceb4',
    'Руманга': '#ffa726',
    'Комикс': '#fc5c65',
    'Видео': '#a55eea'
  };
  return colors[category] || '#666';
};

export default CatalogDropdown;
